/*
 * CUDA Trapezoidal Rule II: Optimized Implementation
 * 
 * This version replaces atomicAdd with shared memory reduction
 * for dramatically improved performance.
 * 
 * Key optimizations:
 * 1. Each thread computes f(x_i) independently
 * 2. Tree-structured reduction within each block (O(log n) steps)
 * 3. Only ONE global write per block (thread 0 writes partial sum)
 * 4. Uses fast on-chip shared memory (~5 cycle latency)
 */

#include <stdio.h>
#include <cuda_runtime.h>

#define CHECK_CUDA(call) \
 do { \
 cudaError_t err = call; \
 if (err != cudaSuccess) { \
 fprintf(stderr, "CUDA error at %s:%d: %s\n", \
 __FILE__, __LINE__, cudaGetErrorString(err)); \
 exit(EXIT_FAILURE); \
 } \
 } while(0)

// Device function: The integrand f(x) = x^2
__device__ double f(double x) {
 return x * x;
}

/*
 * Optimized trapezoidal rule kernel using tree-structured reduction
 * 
 * Parameters:
 * a - Lower bound of integration
 * h - Step size (h = (b-a)/n)
 * n - Number of intervals
 * blockSums - Output array for partial sums from each block
 * 
 * Shared memory: Dynamically allocated, size = threadsPerBlock * sizeof(double)
 */
__global__ void trapReduction(double a, double h, int n, double* blockSums) {
 // Dynamically allocated shared memory
 extern __shared__ double sdata[];

 // Thread and block indices
 unsigned int tid = threadIdx.x;
 unsigned int i = threadIdx.x + blockIdx.x * blockDim.x;

 // Step 1: Each thread computes its contribution independently
 // Initialize to 0 for threads beyond the valid range
 double myVal = 0.0;

 if (i <= n) {
 double x_i = a + i * h;
 myVal = f(x_i);

 // Apply trapezoidal rule boundary weighting
 // First and last points get half weight
 if (i == 0 || i == n) {
 myVal *= 0.5;
 }
 }
 // Threads beyond n contribute 0.0 (harmless to reduction)

 // Step 2: Store value in shared memory
 sdata[tid] = myVal;

 // Synchronize: Ensure all threads have written to shared memory
 // before starting reduction
 __syncthreads();

 // Step 3: Tree-structured parallel reduction
 // Stride-halving pattern: blockDim/2, blockDim/4, ..., 1
 // Each step: thread i adds sdata[i + stride] to sdata[i]
 // 
 // Example with 8 threads:
 // Initial: [v0,v1,v2,v3,v4,v5,v6,v7]
 // stride=4: [v0+v4, v1+v5, v2+v6, v3+v7, -, -, -, -]
 // stride=2: [v0+v4+v2+v6, v1+v5+v3+v7, -, -, -, -, -, -]
 // stride=1: [v0+v1+v2+v3+v4+v5+v6+v7, -, -, -, -, -, -, -]
 //
 for (unsigned int s = blockDim.x / 2; s > 0; s >>= 1) {
 if (tid < s) {
 sdata[tid] += sdata[tid + s];
 }
 // CRITICAL: __syncthreads() must be reached by ALL threads
 // Place it OUTSIDE the if-block to avoid deadlock
 __syncthreads();
 }

 // Step 4: Thread 0 of each block writes the partial sum
 // This is the ONLY write to global memory per block
 // Replaces blockDim.x atomicAdd operations with 1 simple store
 if (tid == 0) {
 blockSums[blockIdx.x] = sdata[0];
 }
}

// Alternative kernel with interleaved addressing (for comparison)
// This version may have more bank conflicts but simpler to understand
__global__ void trapReductionInterleaved(double a, double h, int n, 
 double* blockSums) {
 extern __shared__ double sdata[];

 unsigned int tid = threadIdx.x;
 unsigned int i = threadIdx.x + blockIdx.x * blockDim.x;
 unsigned int idx = tid;

 // Each thread loads its value
 double myVal = 0.0;
 if (i <= n) {
 double x_i = a + i * h;
 myVal = f(x_i);
 if (i == 0 || i == n) myVal *= 0.5;
 }
 sdata[idx] = myVal;
 __syncthreads();

 // Interleaved addressing: threads add with increasing stride
 // stride = 1, 2, 4, 8... (reverse of sequential addressing)
 for (unsigned int s = 1; s < blockDim.x; s *= 2) {
 if ((tid % (2 * s)) == 0 && idx + s < blockDim.x) {
 sdata[idx] += sdata[idx + s];
 }
 __syncthreads();
 }

 if (tid == 0) {
 blockSums[blockIdx.x] = sdata[0];
 }
}

// Host function to perform the complete integration
double integrateOnGPU(double a, double b, int n) {
 double h = (b - a) / n;

 // Use 256 threads per block (power of 2 for clean reduction)
 int threadsPerBlock = 256;

 // Calculate number of blocks needed
 // We have n+1 points (0 to n), need to cover them all
 int numBlocks = (n + 1 + threadsPerBlock - 1) / threadsPerBlock;

 printf(" GPU Configuration:\n");
 printf(" Threads per block: %d\n", threadsPerBlock);
 printf(" Number of blocks: %d\n", numBlocks);
 printf(" Total threads: %d\n", numBlocks * threadsPerBlock);

 // Allocate device memory for block-level partial sums
 double* d_blockSums;
 size_t blockSumsSize = numBlocks * sizeof(double);
 CHECK_CUDA(cudaMalloc(&d_blockSums, blockSumsSize));

 // Calculate shared memory size per block
 int sharedMemBytes = threadsPerBlock * sizeof(double);

 // Launch the optimized kernel
 // Third argument specifies dynamic shared memory size
 trapReduction<<<numBlocks, threadsPerBlock, sharedMemBytes>>>(
 a, h, n, d_blockSums);

 CHECK_CUDA(cudaGetLastError());
 CHECK_CUDA(cudaDeviceSynchronize());

 // Copy block sums back to host
 double* h_blockSums = (double*)malloc(blockSumsSize);
 CHECK_CUDA(cudaMemcpy(h_blockSums, d_blockSums, blockSumsSize, 
 cudaMemcpyDeviceToHost));

 // Final reduction on host (small number of additions)
 // This is fast since numBlocks << n
 double totalSum = 0.0;
 for (int i = 0; i < numBlocks; i++) {
 totalSum += h_blockSums[i];
 }

 // Multiply by step size to get final result
 double result = totalSum * h;

 // Cleanup
 free(h_blockSums);
 CHECK_CUDA(cudaFree(d_blockSums));

 return result;
}

int main() {
 // Integration parameters
 double a = 0.0; // Lower bound
 double b = 1.0; // Upper bound
 int n = 1048576; // Number of intervals (power of 2)

 // Exact answer for f(x) = x^2: ∫x^2 dx = x^3/3
 double exact = (b*b*b - a*a*a) / 3.0;

 printf("========================================\n");
 printf("CUDA Trapezoidal Rule II: Performance Optimization\n");
 printf("========================================\n");
 printf("Integrand: f(x) = x^2\n");
 printf("Interval: [%f, %f]\n", a, b);
 printf("Intervals: %d\n", n);
 printf("Step size h: %.10f\n", (b-a)/n);
 printf("Exact answer: %.10f\n", exact);
 printf("----------------------------------------\n");

 // Run GPU version
 printf("Running GPU kernel with shared memory reduction...\n\n");
 double gpuResult = integrateOnGPU(a, b, n);

 // Calculate error
 double error = fabs(gpuResult - exact);

 printf("----------------------------------------\n");
 printf("RESULTS:\n");
 printf(" GPU Result: %.10f\n", gpuResult);
 printf(" Exact: %.10f\n", exact);
 printf(" Absolute error: %.10e\n", error);
 printf("========================================\n");

 return 0;
}
